#!/bin/bash
# Bilibili Channel Downloader Script
# Target: https://space.bilibili.com/123456789
# Generated by bilibili-downloader skill

# Prerequisites check
echo "Checking prerequisites..."
command -v yt-dlp >/dev/null 2>&1 || { echo "ERROR: yt-dlp not installed. Run: pip install yt-dlp"; exit 1; }
command -v ffmpeg >/dev/null 2>&1 || { echo "ERROR: ffmpeg not installed."; exit 1; }

# Create output directory
mkdir -p ./bilibili_videos

# Download command for User Channel - All Videos
# NOTE: This is a placeholder/test command. Replace with actual URL for real downloads.
yt-dlp --cookies-from-browser chrome \
  --limit-rate 1M \
  --sleep-interval 60 \
  --max-sleep-interval 90 \
  --download-archive ./bilibili_videos/archive.txt \
  -f "bestvideo[height<=1080]+bestaudio/best" \
  -o "./bilibili_videos/%(upload_date>%Y%m%d)s-%(title)s.%(ext)s" \
  "https://space.bilibili.com/123456789"

echo "Download complete. Videos saved to ./bilibili_videos/"
